1	export type QuoteContext = {
2	  yearsWithMHPCO: number;
3	  isFollowUp: boolean;
4	};
5	
6	const POLICY_FEE = 5;
7	
8	const BASE_PREMIUM: Record<string, number> = {
9	  sword: 100,
10	  amulet: 60,
11	  staff: 80,
12	};
13	
14	export function quote(items: { type: string }[], context: QuoteContext): number {
15	  const itemsBasePremium = items.reduce((sum, item) => sum + BASE_PREMIUM[item.type], 0);
16	  return itemsBasePremium + POLICY_FEE;
17	}
18	
19	export function claim(): unknown {
20	  return undefined;
21	}
