1	import { describe, it, expect } from "vitest";
2	import { quote, claim } from "./claim-office.js";
3	
4	describe("Claim Office - quote (premium)", () => {
5	  // Fee-only baseline
6	  it("should charge 5 G (fee only) for an empty item list", () => {
7	    expect(quote([], { yearsWithMHPCO: 0, isFollowUp: false })).toBe(5);
8	  });
9	
10	  // Single main item base premiums + fee
11	  it("should quote a single sword at 105 G (100 base + 5 fee)", () => {
12	    expect(quote([{ type: "sword" }], { yearsWithMHPCO: 0, isFollowUp: false })).toBe(105);
13	  });
14	  it("should quote a single amulet at 65 G (60 base + 5 fee)", () => {
15	    expect(quote([{ type: "amulet" }], { yearsWithMHPCO: 0, isFollowUp: false })).toBe(65);
16	  });
17	  it("should quote a single staff at 85 G (80 base + 5 fee)", () => {
18	    expect(quote([{ type: "staff" }], { yearsWithMHPCO: 0, isFollowUp: false })).toBe(85);
19	  });
20	  it("should quote a single potion at 45 G (40 base + 5 fee)", () => {
21	    expect(quote([{ type: "potion" }], { yearsWithMHPCO: 0, isFollowUp: false })).toBe(45);
22	  });
23	
24	  // Multiple main items sum their base premiums
25	  it.todo("should sum base premiums for a sword and an amulet to 165 G (160 base + 5 fee)");
26	
27	  // Component base premiums
28	  it.todo("should quote a single rune at 30 G (25 base + 5 fee)");
29	  it.todo("should quote 2 runes at 55 G (50 base + 5 fee)");
30	
31	  // Building block of 3 alike components
32	  it.todo("should quote 3 runes as a block at 65 G (60 base + 5 fee)");
33	  it.todo("should quote 4 runes at 105 G (no block, 100 base + 5 fee)");
34	  it.todo("should quote 7 runes at 180 G (175 base + 5 fee)");
35	
36	  // Alike = same type only
37	  it.todo("should not form a block for 2 runes + 1 moonstone (75 base + 5 fee = 80 G)");
38	  it.todo("should form two separate blocks for 3 runes + 3 moonstones (120 base + 5 fee = 125 G)");
39	
40	  // Item-specific modifiers
41	  it.todo("should add 50% curse surcharge to the cursed item's base premium");
42	  it.todo("should add 30% high-enchantment surcharge for enchantment >= 5");
43	  it.todo("should not add high-enchantment surcharge for enchantment 4");
44	  it.todo("should apply both curse and high-enchantment surcharges to a cursed enchantment-5 item");
45	
46	  // Modifier scope on multi-item policies
47	  it.todo("should apply the curse surcharge only to the cursed item, not the whole policy (cursed sword + plain amulet = 210 base before fee)");
48	
49	  // Policy-wide modifiers
50	  it.todo("should apply 20% loyalty discount for a customer with exactly 2 years");
51	  it.todo("should apply 10% first-insurance surcharge to the policy base premium");
52	  it.todo("should apply 15% follow-up discount on quotes after the customer's first quote");
53	
54	  // Rounding up in MHPCO's favor
55	  it.todo("should round the final premium up (197.5 G becomes 198 G)");
56	
57	  // Integration examples
58	  it.todo("should quote a newcomer's cursed steel sword (enchantment 3) at 165 G");
59	  it.todo("should quote a 3-year customer's second-quote cursed steel sword (enchantment 7) at 160 G");
60	
61	  // Error case
62	  it.todo("should reject a quote containing an item with an unknown type");
63	});
