65	describe("Claim Office - claim (payout)", () => {
66	  // Standard reimbursement minus deductible
67	  it.todo("should pay full damage minus 100 G deductible for a regular item (sword, enchantment 3, damage 500 -> 400)");
68	  it.todo("should pay full damage minus 100 G deductible for a component (rune, damage 200 -> 100)");
69	
70	  // High-enchantment clause
71	  it.todo("should reimburse 50% then deduct 100 G for enchantment >= 8 (steel sword, enchantment 9, damage 1000 -> 400)");
72	
73	  // Dragon-material clause
74	  it.todo("should fully reimburse then deduct 100 G for dragon material (dragon sword, enchantment 5, damage 800 -> 700)");
75	
76	  // Conflict: 50% rule wins over dragon
77	  it.todo("should apply the 50% rule (not full) when both high-enchantment >= 8 and dragon apply (dragon sword, enchantment 9, damage 1000 -> 400)");
78	
79	  // Threshold confirmation
80	  it.todo("should treat enchantment exactly 8 as high-enchantment (dragon sword, enchantment 8, damage 1000 -> 400)");
81	
82	  // Deductible per damage event
83	  it.todo("should apply the 100 G deductible once per damaged item (sword 500 + amulet 300 -> 600)");
84	
85	  // Cap behaviour
86	  it.todo("should cap total payout at twice the insurance sum");
87	  it.todo("should share the cap across successive claims and reduce payout to the remaining cap");
88	
89	  // Rounding down in MHPCO's favor
90	  it.todo("should round the final payout down (350.5 G becomes 350 G)");
91	
92	  // Error cases
93	  it.todo("should reject a claim whose damage entry references an item not in the policy");
94	  it.todo("should reject a claim with more damage entries of a type than the policy covers");
95	  it.todo("should reject a claim with a negative damage amount");
96	});
